import re
def camel_to_snake(text):
  str1 = re.sub('(.)([A-Z][a-z]+)', r'\1_\2', text)
  return re.sub('([a-z0-9])([A-Z])', r'\1_\2', str1).lower()

public_tests:
assert camel_to_snake('GoogleAssistant') == 'google_assistant'

assert camel_to_snake('ChromeCast') == 'chrome_cast'

import pytest
from solution import camel_to_snake

def test_boundary_text_empty_string():
    assert camel_to_snake('') == ''

def test_boundary_text_single_char():
    assert camel_to_snake('a') == 'a'

def test_boundary_text_repeated():
    assert camel_to_snake('aaa') == 'aaa'

def test_boundary_text_with_spaces():
    assert camel_to_snake('a b c') == 'a b c'

